3	import {
4	    Box,
5	    Button,
6	    Stack,
7	    Text,
8	    Textarea,
9	    TextInput,
10	    Title,
11	} from '@mantine/core';
12	import { useForm } from '@mantine/form';
13	import { notifications } from '@mantine/notifications';
14	import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
15	import { zod4Resolver } from 'mantine-form-zod-resolver';
16	import { usePathname, useRouter, useSearchParams } from 'next/navigation';
17	import { useEffect, useRef } from 'react';
18	
19	import { EmailInput } from '@/components/EmailInput/EmailInput';
20	import { config } from '@/lib/config';
21	import { toPublicMessage } from '@/lib/errors';
22	import { captureUnexpectedError } from '@/lib/observability/sentry';
23	import {
24	    EnquiryInput,
25	    EnquirySchema,
26	    SendEnquiryProxy,
27	} from '@/types/actions/SendEnquiry';
28	
29	export interface Props {
30	    redirectUrl: string;
31	    onSendEnquiry: SendEnquiryProxy;
32	}
33	
34	export const EnquiryForm = ({ redirectUrl, onSendEnquiry }: Props) => {
35	    const router = useRouter();
36	    const pathname = usePathname();
37	    const searchParams = useSearchParams();
38	    const formRef = useRef<HTMLFormElement>(null);
39	
40	    useEffect(() => {
41	        formRef.current?.setAttribute('data-hydrated', 'true');
42	    }, []);
43	
44	    const form = useForm<EnquiryInput>({
45	        initialValues: {
46	            name: '',
47	            email: '',
48	            message: '',
49	        },
50	        validate: zod4Resolver(EnquirySchema),
51	        validateInputOnBlur: true,
52	    });
53	
54	    useEffect(() => {
55	        const enquiryStatus = searchParams.get('enquiry');
56	        const errorMessage = searchParams.get('error');
57	
58	        if (!enquiryStatus) {
59	            return;
60	        }
61	
62	        if (enquiryStatus === 'verified') {
63	            notifications.show({
64	                color: 'teal',
65	                title: 'Email verified',
66	                message: 'Thanks! Your enquiry has been delivered.',
67	                icon: <IconCheck size={config.notificationIconSize} />,
68	            });
69	        }
70	
71	        if (enquiryStatus === 'error') {
72	            notifications.show({
73	                color: 'red',
74	                title: 'Verification failed',
75	                message: errorMessage ?? 'We could not verify your email.',
76	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
77	            });
78	        }
79	
80	        const updatedParams = new URLSearchParams(searchParams.toString());
81	        updatedParams.delete('enquiry');
82	        updatedParams.delete('error');
83	        const query = updatedParams.toString();
84	        router.replace(query ? `${pathname}?${query}` : pathname);
85	    }, [pathname, router, searchParams]);
86	
87	    const handleSubmit = async (values: EnquiryInput) => {
88	        const id = notifications.show({
89	            loading: true,
90	            title: 'Sending enquiry',
91	            message: 'Sending your message...',
92	            autoClose: false,
93	            withCloseButton: false,
94	        });
95	
96	        try {
97	            await onSendEnquiry(values, redirectUrl);
98	            form.reset();
99	
100	            notifications.update({
101	                id,
102	                color: 'teal',
103	                title: 'Confirm your email',
104	                message: 'Check your inbox and verify your email to deliver the message.',
105	                icon: <IconCheck size={config.notificationIconSize} />,
106	                loading: false,
107	                autoClose: config.notificationAutoClose,
108	            });
109	        } catch (error) {
110	            captureUnexpectedError(error, {
111	                layer: 'client',
112	                component: 'EnquiryForm',
113	                action: 'sendEnquiry',
114	                route: '/footy/contact',
115	                extra: {
116	                    redirectUrl,
117	                },
118	            });
119	            const message = toPublicMessage(error, 'Unable to send your message.');
120	            notifications.update({
121	                id,
122	                color: 'red',
123	                title: 'Error',
124	                message,
125	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
126	                loading: false,
127	                autoClose: false,
128	                withCloseButton: true,
129	            });
130	        }
131	    };
132	
133	    return (
134	        <Box
135	            ref={formRef}
136	            maw={520}
137	            component="form"
138	            onSubmit={form.onSubmit(handleSubmit)}
139	            noValidate
140	        >
141	            <Stack>
142	                <Title order={3}>Get in touch</Title>
143	                <Text>
144	                    Want to join, have a question, or just say hello? Send us a message and we will reply soon.
145	                </Text>
146	                <TextInput
147	                    label="Name"
148	                    required
149	                    {...form.getInputProps('name')}
150	                />
151	                <EmailInput
152	                    label="Email"
153	                    required
154	                    {...form.getInputProps('email')}
155	                />
156	                <Textarea
157	                    label="Message"
158	                    required
159	                    autosize
160	                    minRows={4}
161	                    {...form.getInputProps('message')}
162	                />
163	                <Button type="submit">
164	                    Send message
165	                </Button>
166	            </Stack>
167	        </Box>
168	    );
169	};
