1	import { execSync } from 'node:child_process';
2	
3	/**
4	 * Runs once before any Playwright tests. Seeds the test database so every
5	 * test run starts from a known, deterministic state regardless of how
6	 * playwright is invoked (npx playwright test, CI, etc.).
7	 *
8	 * Schema sync (prisma db push) must happen BEFORE the web server starts to
9	 * avoid disrupting its connection pool. It is NOT done here:
10	 *   - Local: run `npm run setup:playwright` once after docker setup or schema
11	 *     changes, then `npm run build`.
12	 *   - CI: the workflow runs `prisma db push` and `npm run build` before tests.
13	 *
14	 * This function only inserts/replaces data, which is safe while the server
15	 * is running.
16	 */
17	export default function globalSetup() {
18	    console.log('⚙️  Seeding test database...');
19	    if (process.env.CI) {
20	        execSync('npm run seed:ci', { stdio: 'inherit' });
21	    } else {
22	        execSync('npm run seed:playwright', { stdio: 'inherit' });
23	    }
24	    console.log('✅ Test database ready');
25	}
